package examples.range;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

public class IntRangeTest_Example {
    @Test
    void containsIncludesBothBoundaries() {
        IntRange range = new IntRange(3, 5);

        assertTrue(range.contains(3));
        assertTrue(range.contains(5));
        assertFalse(range.contains(2));
        assertFalse(range.contains(6));
    }

    @Test
    void sizeCountsEveryIntegerInRange() {
        assertEquals(3, new IntRange(3, 5).size());
        assertEquals(1, new IntRange(4, 4).size());
    }

    @Test
    void constructorRejectsReversedRange() {
        assertThrows(IllegalArgumentException.class, () -> new IntRange(5, 3));
    }
}

