package examples.text;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertThrows;

public class LabelTest_Example {
    @Test
    void constructorTrimsAndLowercasesValue() {
        Label label = new Label("  READY  ");

        assertEquals("ready", label.value());
    }

    @Test
    void constructorRejectsNullAndBlankValues() {
        assertThrows(IllegalArgumentException.class, () -> new Label(null));
        assertThrows(IllegalArgumentException.class, () -> new Label("   "));
    }
}

