package examples.net;

public final class PortNumber {
    private final int value;

    public PortNumber(int value) {
        if (value < 1 || value > 65535) {
            throw new IllegalArgumentException("invalid port");
        }
        this.value = value;
    }

    public int value() {
        return value;
    }
}

