package examples.net;

import org.junit.Assert;
import org.junit.Test;

public class PortNumberTest_Example {
    @Test
    public void acceptsLowestAndHighestValidPorts() {
        Assert.assertEquals(1, new PortNumber(1).value());
        Assert.assertEquals(65535, new PortNumber(65535).value());
    }

    @Test(expected = IllegalArgumentException.class)
    public void rejectsZero() {
        new PortNumber(0);
    }

    @Test(expected = IllegalArgumentException.class)
    public void rejectsValueAboveMaximum() {
        new PortNumber(65536);
    }
}

