package examples.counter;

public final class Counter {
    private int value;

    public Counter(int initialValue) {
        value = initialValue;
    }

    public int increment() {
        return ++value;
    }

    public int reset() {
        value = 0;
        return value;
    }

    public int value() {
        return value;
    }
}

