package examples.counter;

import org.junit.Assert;
import org.junit.Test;

public class CounterTest_Example {
    @Test
    public void incrementUpdatesAndReturnsCurrentValue() {
        Counter counter = new Counter(4);

        Assert.assertEquals(5, counter.increment());
        Assert.assertEquals(5, counter.value());
    }

    @Test
    public void resetClearsCurrentValue() {
        Counter counter = new Counter(9);

        Assert.assertEquals(0, counter.reset());
        Assert.assertEquals(0, counter.value());
    }
}
